@strawberry.type
class Mutation:
    @strawberry.mutation
    def create_product(self, info: Info, input: ProductInput) -> Product:
        with get_session() as session:
            product = ProductModel(
                name=input.name,
                description=input.description,
                price=input.price,
                seller_id=input.seller_id,
            )
            if input.category_ids:
                categories = (
                    session.query(CategoryModel)
                    .filter(CategoryModel.id.in_(input.category_ids))
                    .all()
                )
                product.categories = categories
            session.add(product)
            session.commit()
            session.refresh(product)
            return Product(
                id=product.id,
                name=product.name,
                description=product.description,
                price=product.price,
            )

    @strawberry.mutation
    def create_seller(self, info: Info, input: SellerInput) -> Seller:
        with get_session() as session:
            seller = SellerModel(
                name=input.name,
                email=input.email,
                rating=input.rating,
            )
            session.add(seller)
            session.commit()
            session.refresh(seller)
            return Seller(
                id=seller.id,
                name=seller.name,
                email=seller.email,
                rating=seller.rating,
            )

    @strawberry.mutation
    def create_category(self, info: Info, input: CategoryInput) -> Category:
        with get_session() as session:
            category = CategoryModel(
                name=input.name,
                description=input.description,
                parent_id=input.parent_id,
            )
            session.add(category)
            session.commit()
            session.refresh(category)
            return Category(
                id=category.id,
                name=category.name,
                description=category.description,
            )

    @strawberry.mutation
    def create_review(self, info: Info, input: ReviewInput) -> Review:
        with get_session() as session:
            review = ReviewModel(
                product_id=input.product_id,
                reviewer_name=input.reviewer_name,
                rating=input.rating,
                comment=input.comment,
            )
            session.add(review)
            session.commit()
            session.refresh(review)
            return Review(
                id=review.id,
                reviewer_name=review.reviewer_name,
                rating=review.rating,
                comment=review.comment,
            )

    @strawberry.mutation
    def add_image(self, info: Info, input: ImageInput) -> Image:
        with get_session() as session:
            image = ImageModel(
                product_id=input.product_id,
                url=input.url,
                alt_text=input.alt_text,
                is_primary=1 if input.is_primary else 0,
            )
            session.add(image)
            session.commit()
            session.refresh(image)
            return Image(
                id=image.id,
                url=image.url,
                alt_text=image.alt_text,
                is_primary=bool(image.is_primary),
            )

    @strawberry.mutation
    def delete_product(self, info: Info, id: int) -> bool:
        with get_session() as session:
            product = session.query(ProductModel).get(id)
            if product:
                session.delete(product)
                session.commit()
                return True
            return False

    @strawberry.mutation
    def update_product(
        self,
        info: Info,
        id: int,
        name: Optional[str] = None,
        description: Optional[str] = None,
        price: Optional[float] = None,
        seller_id: Optional[int] = None,
        category_ids: Optional[List[int]] = None,
    ) -> Optional[Product]:
        with get_session() as session:
            product = session.query(ProductModel).get(id)
            if not product:
                return None
            if name is not None:
                product.name = name
            if description is not None:
                product.description = description
            if price is not None:
                product.price = price
            if seller_id is not None:
                product.seller_id = seller_id
            if category_ids is not None:
                categories = (
                    session.query(CategoryModel)
                    .filter(CategoryModel.id.in_(category_ids))
                    .all()
                )
                product.categories = categories
            session.commit()
            session.refresh(product)
            return Product(
                id=product.id,
                name=product.name,
                description=product.description,
                price=product.price,
            )


def seed_database():
    """Seed the database with sample data."""
    with get_session() as session:
        # Check if data already exists
        if session.query(ProductModel).first():
            return

        # Create sellers
        seller1 = SellerModel(name="TechStore", email="tech@store.com", rating=4.5)
